/*
 * Simplified Diffie-Hellman Key Exchange Implementation
 * Used in IKE (Internet Key Exchange) for IPSec key management
 * 
 * In real-world IPSec, this would use large prime numbers and
 * modular exponentiation with 2048-bit or 4096-bit keys
 */

// Greatest Common Divisor
long long gcd(long long a, long long b) {
 while (b != 0) {
 long long temp = b;
 b = a % b;
 a = temp;
 }
 return a;
}

// Modular Exponentiation: (base^exp) mod mod
// This is the core operation for Diffie-Hellman
long long mod_pow(long long base, long long exp, long long mod) {
 long long result = 1;
 base = base % mod;

 while (exp > 0) {
 // If exp is odd, multiply result with base
 if (exp % 2 == 1) {
 result = (result * base) % mod;
 }
 // exp must be even now
 exp = exp / 2;
 base = (base * base) % mod;
 }
 return result;
}

// Check if a number is prime (simplified for small numbers)
int isPrime(long long n) {
 if (n <= 1) return 0;
 if (n <= 3) return 1;
 if (n % 2 == 0 || n % 3 == 0) return 0;

 for (long long i = 5; i * i <= n; i += 6) {
 if (n % i == 0 || n % (i + 2) == 0)
 return 0;
 }
 return 1;
}

// Generate random private key
long long generate_private_key(long long max) {
 return (rand() % (max - 2)) + 2;
}

// Alice and Bob exchange messages and compute shared secret
void demonstrate_dh_key_exchange() {
 printf("\n========================================\n");
 printf("Diffie-Hellman Key Exchange for IKE\n");
 printf("========================================\n\n");

 // In real IKE, these would be large primes (2048-bit)
 // Using small values for demonstration
 long long prime = 23; // Public prime (p)
 long long generator = 5; // Public generator (g)

 printf("[Step 1] Public Parameters\n");
 printf(" Prime (p): %lld\n", prime);
 printf(" Generator (g): %lld\n", generator);
 printf(" (In real IPSec: 2048-bit prime, generator = 2 or 5)\n\n");

 // Generate private keys
 long long alice_private = generate_private_key(prime);
 long long bob_private = generate_private_key(prime);

 printf("[Step 2] Private Keys Generated\n");
 printf(" Alice's private key: %lld\n", alice_private);
 printf(" Bob's private key: %lld\n\n", bob_private);

 // Calculate public keys
 long long alice_public = mod_pow(generator, alice_private, prime);
 long long bob_public = mod_pow(generator, bob_private, prime);

 printf("[Step 3] Public Keys Exchanged\n");
 printf(" Alice's public key (g^a mod p): %lld\n", alice_public);
 printf(" Bob's public key (g^b mod p): %lld\n\n", bob_public);

 // Exchange and compute shared secret
 long long alice_shared = mod_pow(bob_public, alice_private, prime);
 long long bob_shared = mod_pow(alice_public, bob_private, prime);

 printf("[Step 4] Shared Secret Computed\n");
 printf(" Alice computes: (Bob's public)^Alice's private mod p\n");
 printf(" Alice's shared secret: %lld\n", alice_shared);

 printf(" Bob computes: (Alice's public)^Bob's private mod p\n");
 printf(" Bob's shared secret: %lld\n\n", bob_shared);

 // Verify they match
 if (alice_shared == bob_shared) {
 printf("[SUCCESS] Both shared secrets match!\n");
 printf(" Shared Secret: %lld\n", alice_shared);
 printf(" This secret is now used to derive IPSec encryption keys\n");
 } else {
 printf("[ERROR] Key exchange failed!\n");
 }
}

