import java.util.*;

/**
 * IPSec Policy and Security Association Management
 * Demonstrates how IPSec policies are stored and matched
 * 
 * university 2022 Scheme - Module 5: IP Security
 */

// Enum for IPSec Actions
enum IPSecAction {
 DISCARD, // Drop the packet
 BYPASS, // No IPSec protection
 APPLY // Apply IPSec protection (ESP/AH)
}

// Enum for IPSec Mode
enum IPSecMode {
 TRANSPORT,
 TUNNEL
}

// Enum for Protocol
enum IPSecProtocol {
 AH, // Authentication Header
 ESP // Encapsulating Security Payload
}

/**
 * Represents an IPSec Security Association (SA)
 * Contains all parameters needed for encrypting/decrypting
 */
class SecurityAssociation {
 private int spi; // Security Parameter Index
 private String destinationAddress;
 private IPSecProtocol protocol;
 private IPSecMode mode;
 private byte[] encryptionKey; // 256-bit for AES-256
 private byte[] authenticationKey; // 256-bit for HMAC-SHA256
 private long sequenceNumber;
 private Date createdAt;
 private Date expiresAt;

 public SecurityAssociation(int spi, String destAddr, 
 IPSecProtocol protocol, IPSecMode mode) {
 this.spi = spi;
 this.destinationAddress = destAddr;
 this.protocol = protocol;
 this.mode = mode;
 this.sequenceNumber = 0;
 this.createdAt = new Date();
 // SA expires in 24 hours (simplified)
 this.expiresAt = new Date(System.currentTimeMillis() + 24*60*60*1000);

 // Generate simulated keys
 this.encryptionKey = new byte[32];
 this.authenticationKey = new byte[32];
 new Random().nextBytes(encryptionKey);
 new Random().nextBytes(authenticationKey);
 }

 // Getters
 public int getSpi() { return spi; }
 public String getDestinationAddress() { return destinationAddress; }
 public IPSecProtocol getProtocol() { return protocol; }
 public IPSecMode getMode() { return mode; }
 public byte[] getEncryptionKey() { return encryptionKey; }
 public byte[] getAuthenticationKey() { return authenticationKey; }
 public long getNextSequenceNumber() { return ++sequenceNumber; }
 public boolean isValid() { return new Date().before(expiresAt); }

 @Override
 public String toString() {
 return String.format("SA[SPI=0x%08X, Dest=%s, Protocol=%s, Mode=%s, Seq=%d]",
 spi, destinationAddress, protocol, mode, sequenceNumber);
 }
}

/**
 * Represents a Policy Entry in the Security Policy Database (SPD)
 */
class SecurityPolicy {
 private String sourcePrefix;
 private String destinationPrefix;
 private int protocol; // TCP=6, UDP=17, ICMP=1, etc.
 private int sourcePort;
 private int destinationPort;
 private IPSecAction action;
 private IPSecProtocol secProtocol; // ESP or AH
 private IPSecMode mode; // Transport or Tunnel
 private String saId; // Associated SA identifier

 public SecurityPolicy(String src, String dst, int proto, 
 IPSecAction action, IPSecProtocol secProto, 
 IPSecMode mode) {
 this.sourcePrefix = src;
 this.destinationPrefix = dst;
 this.protocol = proto;
 this.action = action;
 this.secProtocol = secProto;
 this.mode = mode;
 this.saId = null;
 }

 // Check if this policy matches a packet
 public boolean matches(String srcIp, String dstIp, int proto, 
 int srcPort, int dstPort) {
 return this.sourcePrefix.equals(srcIp) &&
 this.destinationPrefix.equals(dstIp) &&
 this.protocol == proto;
 }

 // Getters
 public IPSecAction getAction() { return action; }
 public IPSecProtocol getSecProtocol() { return secProtocol; }
 public IPSecMode getMode() { return mode; }
 public String getSaId() { return saId; }
 public void setSaId(String saId) { this.saId = saId; }

 @Override
 public String toString() {
 return String.format("Policy[%s:%s->%s proto=%d Action=%s %s %s]",
 sourcePrefix, destinationPrefix, protocol, 
 action, secProtocol, mode);
 }
}

/**
 * Security Policy Database (SPD) - Manages all policies
 */
class SecurityPolicyDatabase {
 private List<SecurityPolicy> policies;

 public SecurityPolicyDatabase() {
 this.policies = new ArrayList<>();
 }

 public void addPolicy(SecurityPolicy policy) {
 policies.add(policy);
 }

 public SecurityPolicy lookup(String srcIp, String dstIp, int proto,
 int srcPort, int dstPort) {
 // More specific policies should be checked first
 for (SecurityPolicy policy : policies) {
 if (policy.matches(srcIp, dstIp, proto, srcPort, dstPort)) {
 return policy;
 }
 }
 return null; // No matching policy - default behavior
 }

 public void printPolicies() {
 System.out.println("\n=== Security Policy Database ===");
 for (SecurityPolicy p : policies) {
 System.out.println(p);
 }
 }
}

/**
 * Security Association Database (SAD) - Manages all SAs
 */
class SecurityAssociationDatabase {
 private Map<Integer, SecurityAssociation> sad;

 public SecurityAssociationDatabase() {
 this.sad = new HashMap<>();
 }

 public void addSA(SecurityAssociation sa) {
 sad.put(sa.getSpi(), sa);
 }

 public SecurityAssociation getSA(int spi) {
 SecurityAssociation sa = sad.get(spi);
 if (sa != null && sa.isValid()) {
 return sa;
 }
 return null; // SA expired or not found
 }

 public void printSAs() {
 System.out.println("\n=== Security Association Database ===");
 for (SecurityAssociation sa : sad.values()) {
 System.out.println(sa);
 }
 }
}

/**
 * Main demonstration class
 */
public class IPSecPolicyManager {

 public static void main(String[] args) {
 System.out.println("========================================");
 System.out.println("IPSec Policy and SA Management Demo");
 System.out.println("university 2022 Scheme - Module 5");
 System.out.println("========================================");

 // Create SPD and SAD
 SecurityPolicyDatabase spd = new SecurityPolicyDatabase();
 SecurityAssociationDatabase sad = new SecurityAssociationDatabase();

 // Configure IPSec Policies
 System.out.println("\n[1] Configuring IPSec Policies...");

 // Policy 1: Encrypt all traffic from HQ to Branch
 SecurityPolicy policy1 = new SecurityPolicy(
 "10.0.1.0/24", "10.0.2.0/24", // Source -> Destination
 0, // All protocols
 IPSecAction.APPLY, // Apply IPSec
 IPSecProtocol.ESP, // Use ESP
 IPSecMode.TUNNEL // Tunnel mode
 );
 policy1.setSaId("HQ-BRANCH-TUNNEL");
 spd.addPolicy(policy1);
 System.out.println(" Added: VPN tunnel between HQ and Branch");

 // Policy 2: Discard traffic from suspicious network
 SecurityPolicy policy2 = new SecurityPolicy(
 "192.168.100.0/24", "10.0.0.0/8",
 0,
 IPSecAction.DISCARD, // Drop
 null, null
 );
 spd.addPolicy(policy2);
 System.out.println(" Added: Block traffic from suspicious network");

 // Policy 3: Allow HTTP/HTTPS without IPSec (bypass)
 SecurityPolicy policy3 = new SecurityPolicy(
 "10.0.0.0/8", "0.0.0.0/0",
 6, // TCP
 IPSecAction.BYPASS, // No encryption
 null, null
 );
 spd.addPolicy(policy3);
 System.out.println(" Added: Bypass for web traffic (demo)");

 // Create Security Associations
 System.out.println("\n[2] Establishing Security Associations...");

 // SA for VPN tunnel
 SecurityAssociation sa1 = new SecurityAssociation(
 0x12345678, // SPI
 "10.0.2.1", // Remote endpoint
 IPSecProtocol.ESP, // ESP protocol
 IPSecMode.TUNNEL // Tunnel mode
 );
 sad.addSA(sa1);
 System.out.println(" Established SA: " + sa1);

 // Print SPD and SAD
 spd.printPolicies();
 sad.printSAs();

 // Demonstrate packet processing
 System.out.println("\n[3] Processing Outbound Packets...\n");

 // Scenario 1: HQ to Branch traffic (should be encrypted)
 String packet1_src = "10.0.1.100";
 String packet1_dst = "10.0.2.50";

 System.out.println("Packet 1: " + packet1_src + " -> " + packet1_dst);
 SecurityPolicy p1 = spd.lookup(packet1_src, packet1_dst, 6, 12345, 80);

 if (p1 != null) {
 switch (p1.getAction()) {
 case APPLY:
 System.out.println(" → Policy: APPLY IPSec (" + 
 p1.getSecProtocol() + " " + p1.getMode() + ")");
 System.out.println(" → Looking up SA with SPI: 0x12345678");
 SecurityAssociation sa = sad.getSA(0x12345678);
 if (sa != null) {
 long seq = sa.getNextSequenceNumber();
 System.out.println(" → Using Sequence Number: " + seq);
 System.out.println(" → Encrypting payload with ESP...");
 System.out.println(" ✓ Packet protected with IPSec!");
 }
 break;
 case DISCARD:
 System.out.println(" → Policy: DISCARD");
 System.out.println(" ✗ Packet dropped!");
 break;
 case BYPASS:
 System.out.println(" → Policy: BYPASS (no encryption)");
 System.out.println(" → Packet sent without IPSec");
 break;
 }
 }

 // Scenario 2: Attack from suspicious network
 String packet2_src = "192.168.100.50";
 String packet2_dst = "10.0.1.10";

 System.out.println("\nPacket 2: " + packet2_src + " -> " + packet2_dst);
 SecurityPolicy p2 = spd.lookup(packet2_src, packet2_dst, 6, 54321, 22);

 if (p2 != null && p2.getAction() == IPSecAction.DISCARD) {
 System.out.println(" → Policy: DISCARD");
 System.out.println(" ✗ Packet dropped by IPSec policy!");
 }

 System.out.println("\n========================================");
 System.out.println("Summary: IPSec Policy & SA Management");
 System.out.println("========================================");
 System.out.println("• SPD: Defines WHAT traffic gets protected");
 System.out.println("• SAD: Contains HOW to protect (keys, algorithms)");
 System.out.println("• IKE: Negotiates SA parameters and keys");
 System.out.println("• ESP: Provides encryption and authentication");
 }
}
